"use client";

import React, { useState } from 'react';
import axios from 'axios';
import { useRouter } from 'next/navigation';

export default function AddMedicationPage() {
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    
    // 요일 목록
    const dayOptions = [
        { label: '월', value: 'MON' },
        { label: '화', value: 'TUE' },
        { label: '수', value: 'WED' },
        { label: '목', value: 'THU' },
        { label: '금', value: 'FRI' },
        { label: '토', value: 'SAT' },
        { label: '일', value: 'SUN' }
    ];

    const [formData, setFormData] = useState({
        medicineName: '',
        intakeTime: '09:00', // 기본값 9시
        selectedDays: [] as string[],
        isKakaoAlert: true
    });

    const themeColor = '#4f46e5'; // Indigo

    // 요일 선택 핸들러
    const toggleDay = (day: string) => {
        setFormData(prev => ({
            ...prev,
            selectedDays: prev.selectedDays.includes(day)
                ? prev.selectedDays.filter(d => d !== day)
                : [...prev.selectedDays, day]
        }));
    };

    // 등록 요청
    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (formData.selectedDays.length === 0) return alert("복용 요일을 하나 이상 선택해주세요.");

        setLoading(true);
        const token = localStorage.getItem('token');

        try {
            await axios.post('http://localhost:8080/api/medication', {
                medicineName: formData.medicineName,
                intakeTime: formData.intakeTime + ":00", // DB 저장을 위해 초(ss) 추가
                intakeDays: formData.selectedDays.join(','), // "MON,WED,FRI" 형태
                isKakaoAlert: formData.isKakaoAlert
            }, {
                headers: { Authorization: `Bearer ${token}` }
            });

            alert("✅ 복약 알림이 등록되었습니다!");
            router.push('/main');
        } catch (error) {
            console.error(error);
            alert("등록 중 오류가 발생했습니다.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '40px 20px', maxWidth: '500px', margin: '0 auto', fontFamily: 'inherit' }}>
            <h1 style={{ fontSize: '24px', fontWeight: '800', marginBottom: '30px', textAlign: 'center' }}>
                💊 새 복약 알림 등록
            </h1>

            <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                {/* 약 이름 입력 */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                    <label style={{ fontSize: '14px', fontWeight: 'bold', color: '#475569' }}>어떤 약인가요?</label>
                    <input
                        type="text"
                        placeholder="예: 타이레놀, 아침 영양제"
                        required
                        style={{ padding: '12px', borderRadius: '8px', border: '1px solid #cbd5e1', fontSize: '16px' }}
                        value={formData.medicineName}
                        onChange={(e) => setFormData({ ...formData, medicineName: e.target.value })}
                    />
                </div>

                {/* 시간 선택 */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                    <label style={{ fontSize: '14px', fontWeight: 'bold', color: '#475569' }}>언제 복용하시나요?</label>
                    <input
                        type="time"
                        required
                        style={{ padding: '12px', borderRadius: '8px', border: '1px solid #cbd5e1', fontSize: '16px' }}
                        value={formData.intakeTime}
                        onChange={(e) => setFormData({ ...formData, intakeTime: e.target.value })}
                    />
                </div>

                {/* 요일 선택 */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                    <label style={{ fontSize: '14px', fontWeight: 'bold', color: '#475569' }}>복용 요일을 선택하세요</label>
                    <div style={{ display: 'flex', justifyContent: 'space-between', gap: '5px' }}>
                        {dayOptions.map((day) => (
                            <button
                                key={day.value}
                                type="button"
                                onClick={() => toggleDay(day.value)}
                                style={{
                                    flex: 1,
                                    padding: '10px 0',
                                    borderRadius: '6px',
                                    border: '1px solid',
                                    borderColor: formData.selectedDays.includes(day.value) ? themeColor : '#cbd5e1',
                                    backgroundColor: formData.selectedDays.includes(day.value) ? themeColor : '#fff',
                                    color: formData.selectedDays.includes(day.value) ? '#fff' : '#475569',
                                    cursor: 'pointer',
                                    fontWeight: 'bold',
                                    fontSize: '14px',
                                    transition: 'all 0.2s'
                                }}
                            >
                                {day.label}
                            </button>
                        ))}
                    </div>
                </div>

                {/* 알림 토글 */}
                <div style={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    justifyContent: 'space-between', 
                    padding: '15px', 
                    backgroundColor: '#f8fafc', 
                    borderRadius: '8px',
                    marginTop: '10px'
                }}>
                    <div>
                        <div style={{ fontWeight: 'bold', fontSize: '15px' }}>카카오톡 알림 받기</div>
                        <div style={{ fontSize: '12px', color: '#64748b' }}>설정한 시간에 카톡으로 알려드려요.</div>
                    </div>
                    <input 
                        type="checkbox" 
                        style={{ width: '20px', height: '20px', cursor: 'pointer' }}
                        checked={formData.isKakaoAlert}
                        onChange={(e) => setFormData({ ...formData, isKakaoAlert: e.target.checked })}
                    />
                </div>

                {/* 제출 버튼 */}
                <button
                    type="submit"
                    disabled={loading}
                    style={{
                        marginTop: '20px',
                        padding: '15px',
                        backgroundColor: loading ? '#ccc' : themeColor,
                        color: '#fff',
                        border: 'none',
                        borderRadius: '8px',
                        fontSize: '18px',
                        fontWeight: 'bold',
                        cursor: loading ? 'not-allowed' : 'pointer'
                    }}
                >
                    {loading ? "등록 중..." : "알림 등록하기"}
                </button>
            </form>

            <div style={{ marginTop: '20px', textAlign: 'center' }}>
                <a href="/main" style={{ color: '#64748b', textDecoration: 'none', fontSize: '14px' }}>취소하고 돌아가기</a>
            </div>
        </div>
    );
}